use serde::{Deserialize, Serialize};

/// Visual-only firework shape categories.
#[derive(Clone, Copy, Debug, Deserialize, Eq, PartialEq, Serialize)]
pub enum ShapeKind {
    Peony,
    Saturn,
    Willow,
    Ring,
    Nested,
    Surface,
}

/// Abstract color families. These are display categories, not material recipes.
#[derive(Clone, Copy, Debug, Deserialize, Eq, PartialEq, Serialize)]
pub enum ColorFamily {
    Warm,
    Cool,
    Green,
    Violet,
    White,
    Gold,
}

/// Visual timing envelopes only.
#[derive(Clone, Copy, Debug, Deserialize, Eq, PartialEq, Serialize)]
pub enum BurnProfile {
    Crisp,
    Soft,
    Trailing,
    Pulsed,
}

#[derive(Clone, Copy, Debug, Deserialize, PartialEq, Serialize)]
pub struct StarVector {
    pub x: f32,
    pub y: f32,
    pub z: f32,
    pub tick: u16,
}

#[derive(Clone, Debug, Deserialize, PartialEq, Serialize)]
pub struct StarPath {
    pub color: ColorFamily,
    pub burn: BurnProfile,
    pub points: Vec<StarVector>,
}

#[derive(Clone, Debug, Deserialize, PartialEq, Serialize)]
pub struct FireworkDesign {
    pub shape: ShapeKind,
    pub symmetry_samples: u16,
    pub hang_time_ticks: u16,
    pub paths: Vec<StarPath>,
}

#[derive(Clone, Copy, Debug, Deserialize, PartialEq, Serialize)]
pub struct TopologyMetrics {
    pub radial_balance: f32,
    pub boundary_persistence: f32,
    pub pairwise_separation: f32,
    pub color_variety: f32,
}

#[derive(Clone, Copy, Debug, Deserialize, PartialEq, Serialize)]
pub struct FireworkScore {
    pub metrics: TopologyMetrics,
    pub total: f32,
}

pub fn score_design(design: &FireworkDesign) -> FireworkScore {
    let metrics = TopologyMetrics {
        radial_balance: radial_balance_score(design),
        boundary_persistence: boundary_persistence_score(design),
        pairwise_separation: pairwise_separation_score(design),
        color_variety: color_variety_score(design),
    };
    let total = (metrics.radial_balance
        + metrics.boundary_persistence
        + metrics.pairwise_separation
        + metrics.color_variety)
        / 4.0;

    FireworkScore { metrics, total }
}

fn radial_balance_score(design: &FireworkDesign) -> f32 {
    let required_samples = match design.shape {
        ShapeKind::Nested | ShapeKind::Surface => 24.0,
        _ => 12.0,
    };
    (f32::from(design.symmetry_samples) / required_samples).clamp(0.0, 1.0)
}

fn boundary_persistence_score(design: &FireworkDesign) -> f32 {
    let longest_tick = design
        .paths
        .iter()
        .flat_map(|path| path.points.iter().map(|point| point.tick))
        .max()
        .unwrap_or(0);
    let observed = longest_tick.max(design.hang_time_ticks);
    (f32::from(observed) / 12.0).clamp(0.0, 1.0)
}

fn pairwise_separation_score(design: &FireworkDesign) -> f32 {
    let endpoints: Vec<StarVector> = design
        .paths
        .iter()
        .filter_map(|path| path.points.last().copied())
        .collect();

    if endpoints.len() < 2 {
        return 1.0;
    }

    let mut separated_pairs = 0usize;
    let mut total_pairs = 0usize;
    for (left_index, left) in endpoints.iter().enumerate() {
        for right in endpoints.iter().skip(left_index + 1) {
            total_pairs += 1;
            if squared_distance(*left, *right) >= 0.04 {
                separated_pairs += 1;
            }
        }
    }

    separated_pairs as f32 / total_pairs as f32
}

fn color_variety_score(design: &FireworkDesign) -> f32 {
    let mut families = Vec::new();
    for path in &design.paths {
        if !families.contains(&path.color) {
            families.push(path.color);
        }
    }
    (families.len() as f32 / 6.0).clamp(0.0, 1.0)
}

fn squared_distance(left: StarVector, right: StarVector) -> f32 {
    let dx = left.x - right.x;
    let dy = left.y - right.y;
    let dz = left.z - right.z;
    dx * dx + dy * dy + dz * dz
}

#[cfg(test)]
mod tests {
    use super::*;

    fn path(color: ColorFamily, x: f32, y: f32) -> StarPath {
        StarPath {
            color,
            burn: BurnProfile::Trailing,
            points: vec![
                StarVector {
                    x: 0.0,
                    y: 0.0,
                    z: 0.0,
                    tick: 0,
                },
                StarVector {
                    x,
                    y,
                    z: 0.0,
                    tick: 10,
                },
            ],
        }
    }

    #[test]
    fn scores_balanced_abstract_design_highly() {
        let design = FireworkDesign {
            shape: ShapeKind::Saturn,
            symmetry_samples: 12,
            hang_time_ticks: 10,
            paths: vec![
                path(ColorFamily::Warm, 1.0, 0.0),
                path(ColorFamily::Cool, -1.0, 0.0),
                path(ColorFamily::Green, 0.0, 1.0),
                path(ColorFamily::Violet, 0.0, -1.0),
            ],
        };

        let score = score_design(&design);

        assert_eq!(score.metrics.radial_balance, 1.0);
        assert_eq!(score.metrics.pairwise_separation, 1.0);
        assert!(score.total > 0.75);
    }

    #[test]
    fn penalizes_overlapping_trajectory_endpoints() {
        let design = FireworkDesign {
            shape: ShapeKind::Peony,
            symmetry_samples: 6,
            hang_time_ticks: 2,
            paths: vec![
                path(ColorFamily::Warm, 0.1, 0.1),
                path(ColorFamily::Warm, 0.11, 0.1),
            ],
        };

        let score = score_design(&design);

        assert_eq!(score.metrics.pairwise_separation, 0.0);
        assert!(score.total < 0.5);
    }
}
